<script lang="ts">
  import type { TraceJson, Message } from './lib/types'
  import { scrollToHash, setupHashListener } from './lib/hash-nav'
  import { getTimestampInfo } from './lib/timestamp-utils'
  import MessageView from './components/MessageView.svelte'
  import FileBrowser from './components/FileBrowser.svelte'
  import GitHubBrowser from './components/GitHubBrowser.svelte'
  import LocalBrowser from './components/LocalBrowser.svelte'
  import FimPreview from './components/FimPreview.svelte'
  import RewritePreview from './components/RewritePreview.svelte'
  import ModelInfo from './components/ModelInfo.svelte'
  import 'highlight.js/styles/github-dark.css'

  let messages: Message[] = $state([])
  let modelInfo: { model?: string; isAvailable: boolean } = $state({
    model: undefined,
    isAvailable: false
  })
  let loading = $state(true)
  let error = $state<string | null>(null)
  let traceUrl = $state<string | null>(null)
  let isDirectory = $state(false)
  let githubPath = $state<string | null>(null) // e.g., "g0t4/dataset-gfy/master/path/to/file"
  let localPath = $state<string | null>(null) // e.g., "semantic_grep_auto_context/fims"

  // Decoded URL for display
  const displayUrl = $derived(
    localPath
      ? `local → ${localPath || '(root)'}`
      : githubPath
        ? `github.com/${githubPath.split('/').slice(0, 2).join('/')} → ${githubPath.split('/').slice(3).join('/')}`
        : traceUrl
          ? decodeURIComponent(traceUrl)
          : null
  )

  // Derive title from trace URL
  const pageTitle = $derived.by(() => {
    if (!traceUrl) return 'Chat Viewer'
    if (isDirectory) return 'File Browser'
    const url = traceUrl.toLowerCase()
    if (url.includes('rewrite')) return ':AskRewrite'
    if (url.includes('tools')) return ':AskAgent /tools'
    if (url.includes('question')) return ':AskAgent'
    if (url.includes('agents')) return ':AskAgent'
    if (url.includes('fim')) return ':AskPredict'
    return 'Chat Viewer'
  })

  // Extract timestamp info from filename
  const traceTimestampInfo = $derived.by(() => {
    if (isDirectory) return null

    // Try to get filename from localPath or githubPath
    let filename = ''
    if (localPath) {
      filename = localPath.split('/').pop() || ''
    } else if (githubPath) {
      filename = githubPath.split('/').pop() || ''
    } else if (traceUrl) {
      // Try to extract from URL
      filename = traceUrl.split('/').pop()?.split('?')[0] || ''
    }

    if (!filename) return null
    return getTimestampInfo(filename)
  })

  // Detect if this is a FIM trace and extract data for preview
  const fimData = $derived.by(() => {
    if (pageTitle !== ':AskPredict' || messages.length === 0) return null

    // Find the last user message (actual prompt, not RAG context)
    const lastUserMessage = messages.findLast(msg => msg.role === 'user')
    if (!lastUserMessage) return null

    // Check if it contains the FIM prompt
    const content = typeof lastUserMessage.content === 'string' ? lastUserMessage.content : ''
    if (!content.includes('<|fim_middle|>')) return null

    // Find the assistant's response
    const assistantMessage = messages.find(msg => msg.role === 'assistant')
    if (!assistantMessage) return null

    // Extract the non-thinking content from assistant response
    let assistantContent = ''
    if (typeof assistantMessage.content === 'string') {
      assistantContent = assistantMessage.content
    } else if (Array.isArray(assistantMessage.content)) {
      // Filter out thinking blocks
      assistantContent = assistantMessage.content
        .filter((block: any) => block.type === 'text')
        .map((block: any) => block.text)
        .join('')
    }

    return {
      userMessage: content,
      assistantResponse: assistantContent.trim()
    }
  })

  // Detect if this is an AskRewrite trace and extract data for preview
  const rewriteData = $derived.by(() => {
    if (pageTitle !== ':AskRewrite' || messages.length === 0) return null

    // Find the last user message
    const lastUserMessage = messages.findLast(msg => msg.role === 'user')
    if (!lastUserMessage) return null

    const userContent = typeof lastUserMessage.content === 'string' ? lastUserMessage.content : ''

    // Find the assistant's response
    const assistantMessage = messages.find(msg => msg.role === 'assistant')
    if (!assistantMessage) return null

    // Extract the non-thinking content from assistant response
    let assistantContent = ''
    if (typeof assistantMessage.content === 'string') {
      assistantContent = assistantMessage.content
    } else if (Array.isArray(assistantMessage.content)) {
      // Filter out thinking blocks
      assistantContent = assistantMessage.content
        .filter((block: any) => block.type === 'text')
        .map((block: any) => block.text)
        .join('')
    }

    return {
      userMessage: userContent,
      assistantResponse: assistantContent
    }
  })

  async function loadTrace(url: string) {
    loading = true
    error = null
    try {
      const res = await fetch(url)
      if (!res.ok) throw new Error(`Failed to fetch: ${res.status}`)

      // Detect format based on URL
      const isJsonl = url.includes('-messages.jsonl')

      if (isJsonl) {
        // JSONL format: one message per line
        const text = await res.text()
        const lines = text.trim().split('\n')
        messages = lines
          .filter(line => line.trim())
          .map(line => JSON.parse(line))
      } else {
        // *-trace.json
        const data: TraceJson = await res.json()

        // Extract messages from request_body
        messages = data.request_body?.messages ?? []

        // Check for model info in trace metadata
        if (data.last_sse?.model) {
          modelInfo = {
            model: data.last_sse.model,
            isAvailable: true
          }
        }

        // Append response_message if present
        if (data.response_message) {
          messages = [...messages, data.response_message]
        }
      }
    } catch (e) {
      error = e instanceof Error ? e.message : 'Unknown error'
    } finally {
      loading = false
    }
  }

  // Detect if URL is a directory based on path heuristics
  function isDirectoryUrl(url: string): boolean {
    // Ends with / = directory
    if (url.endsWith('/')) return true

    // Extract the last path segment (works with both URLs and plain paths)
    let lastSegment = ''
    try {
      // Try parsing as URL first
      const urlObj = new URL(url)
      lastSegment = urlObj.pathname.split('/').filter(Boolean).pop() || ''
    } catch {
      // Not a URL, treat as plain path
      lastSegment = url.split('/').filter(Boolean).pop() || ''
    }

    // No extension = directory (e.g., "2026-01-19_002")
    // Has extension = file (e.g., ".json", ".txt", etc.)
    if (!lastSegment.includes('.')) return true

    return false
  }

  // Load from URL param on mount
  $effect(() => {
    const params = new URLSearchParams(window.location.search)

    // New github= parameter (e.g., ?github=g0t4/dataset-gfy/master/path/to/file)
    const githubParam = params.get('github')

    // Dev-only local= parameter (e.g., ?local=semantic_grep_auto_context/fims)
    const localParam = params.get('local')

    // Legacy url= parameter (backward compat, files only)
    const urlParam = params.get('url')

    if (githubParam) {
      // Parse github=owner/repo/branch/path
      githubPath = githubParam
      localPath = null
      const parts = githubParam.split('/')
      if (parts.length < 3) {
        error = 'Invalid github parameter format. Expected: owner/repo/branch/path'
        loading = false
        return
      }

      const owner = parts[0]
      const repo = parts[1]
      const branch = parts[2]
      const path = parts.slice(3).join('/')

      // Use path heuristics to detect directory
      isDirectory = isDirectoryUrl(path)

      if (isDirectory) {
        // Directory - will use GitHubBrowser
        loading = false
      } else {
        // File - fetch from jsDelivr CDN
        const cdnUrl = `https://cdn.jsdelivr.net/gh/${owner}/${repo}@${branch}/${path}`
        traceUrl = cdnUrl
        loadTrace(cdnUrl)
      }
    } else if (localParam && import.meta.env.MODE === 'development') {
      // Dev-only local= parameter
      localPath = localParam
      githubPath = null

      // Use path heuristics to detect directory
      isDirectory = isDirectoryUrl(localParam)

      if (isDirectory) {
        // Directory - will use LocalBrowser
        loading = false
      } else {
        // File - fetch via API endpoint
        traceUrl = `/api/local/file?path=${encodeURIComponent(localParam)}`
        loadTrace(traceUrl)
      }
    } else if (urlParam) {
      // Legacy url= parameter (files only, no directory browsing)
      traceUrl = urlParam
      githubPath = null
      localPath = null
      isDirectory = false
      loadTrace(urlParam)
    } else {
      loading = false
      error =
        import.meta.env.MODE === 'development'
          ? 'Provide a ?github=, ?url=, or ?local= parameter.'
          : 'Provide a ?github= or ?url= parameter.'
    }
  })

  // Scroll to hash after content loads
  $effect(() => {
    if (!loading && messages.length > 0) {
      // Delay to ensure DOM is rendered
      setTimeout(scrollToHash, 100)
    }
  })

  // Listen for hash changes
  $effect(() => {
    return setupHashListener()
  })

  // Update document title when pageTitle changes
  $effect(() => {
    document.title = pageTitle
  })
</script>

<main class="max-w-7xl mx-auto p-4">
  <header class="mb-6">
    <div class="flex items-baseline gap-3">
      <h1 class="text-2xl font-bold text-gray-100">{pageTitle}</h1>
      {#if traceTimestampInfo}
        <span class="text-sm text-gray-500">
          {traceTimestampInfo.dateTime} <span class={traceTimestampInfo.colorClass}>({traceTimestampInfo.age})</span>
        </span>
      {/if}
    </div>
    {#if displayUrl}
      <p class="text-sm text-gray-500 truncate mt-1">{displayUrl}</p>
    {/if}
  </header>

  {#if loading}
    <div class="text-gray-400">Loading...</div>
  {:else if error}
    <div class="text-red-400 bg-red-900/20 p-4 rounded">{error}</div>
  {:else if isDirectory && localPath}
    <LocalBrowser localPath={localPath} />
  {:else if isDirectory && githubPath}
    <GitHubBrowser githubPath={githubPath} />
  {:else if isDirectory && traceUrl}
    <FileBrowser url={traceUrl} />
  {:else}
    {#if modelInfo.isAvailable}
      <ModelInfo model={modelInfo.model} />
    {/if}

    {#if fimData}
      <FimPreview userMessage={fimData.userMessage} assistantResponse={fimData.assistantResponse} />
    {/if}

    {#if rewriteData}
      <RewritePreview userMessage={rewriteData.userMessage} assistantResponse={rewriteData.assistantResponse} />
    {/if}

    <div class="space-y-4">
      {#each messages as msg, idx}
        <MessageView message={msg} index={idx + 1} />
      {/each}
    </div>
  {/if}
</main>
